#include <bits/stdc++.h>
using namespace std;

const int N=150;

int n,s[N][N],f[N],ans=-2e9;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++){
            scanf("%d",&s[i][j]);
            s[i][j]=s[i][j]+s[i-1][j]+s[i][j-1]-s[i-1][j-1];
        }
    for(int u=1;u<=n;u++)
        for(int d=u;d<=n;d++){
            f[0]=-2e9;
            for(int i=1;i<=n;i++){
                f[i]=max(f[i-1],0)+(s[d][i]-s[u-1][i]-s[d][i-1]+s[u-1][i-1]);
                ans=max(ans,f[i]);
            }
        }
    printf("%d",ans);
    return 0;
}
